1670       return nullptr;
1671 
1672     ConstOps.push_back(C);
1673   }
1674 
1675   return ConstantFoldInstOperands(&I, ConstOps, I.getDataLayout());
1676 }
1677 
1678 static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
1679                                              Value *NewOp, InstCombiner &IC) {
1680   Instruction *Clone = I.clone();
1681   Clone->replaceUsesOfWith(SI, NewOp);
1682   Clone->dropUBImplyingAttrsAndMetadata();
1683   IC.InsertNewInstBefore(Clone, SI->getIterator());
1684   return Clone;
1685 }
1686 
1687 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
1688                                                 bool FoldWithMultiUse) {
1689   // Don't modify shared select instructions unless set FoldWithMultiUse
1690   if (!SI->hasOneUse() && !FoldWithMultiUse)
1691     return nullptr;
1692 
1693   Value *TV = SI->getTrueValue();
1694   Value *FV = SI->getFalseValue();
1695   if (!(isa<Constant>(TV) || isa<Constant>(FV)))
1696     return nullptr;
1697 
1698   // Bool selects with constant operands can be folded to logical ops.
1699   if (SI->getType()->isIntOrIntVectorTy(1))
1700     return nullptr;
1701 
1702   // Test if a FCmpInst instruction is used exclusively by a select as
1703   // part of a minimum or maximum operation. If so, refrain from doing
1704   // any other folding. This helps out other analyses which understand
1705   // non-obfuscated minimum and maximum idioms. And in this case, at
1706   // least one of the comparison operands has at least one user besides
1707   // the compare (the select), which would often largely negate the
1708   // benefit of folding anyway.
1709   if (auto *CI = dyn_cast<FCmpInst>(SI->getCondition())) {
1710     if (CI->hasOneUse()) {
1711       Value *Op0 = CI->getOperand(0), *Op1 = CI->getOperand(1);
1712       if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1))
1713         return nullptr;
1714     }
1715   }
1716 
1717   // Make sure that one of the select arms constant folds successfully.
1718   Value *NewTV = constantFoldOperationIntoSelectOperand(Op, SI, /*IsTrueArm*/ true);
1719   Value *NewFV = constantFoldOperationIntoSelectOperand(Op, SI, /*IsTrueArm*/ false);
1720   if (!NewTV && !NewFV)
1721     return nullptr;
1722 
1723   // Create an instruction for the arm that did not fold.
1724   if (!NewTV)
1725     NewTV = foldOperationIntoSelectOperand(Op, SI, TV, *this);
1726   if (!NewFV)
1727     NewFV = foldOperationIntoSelectOperand(Op, SI, FV, *this);
1728   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
1729 }
1730 
1731 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
1732                                          Value *InValue, BasicBlock *InBB,
1733                                          const DataLayout &DL,
1734                                          const SimplifyQuery SQ) {
1735   // NB: It is a precondition of this transform that the operands be
1736   // phi translatable!
1737   SmallVector<Value *> Ops;
1738   for (Value *Op : I.operands()) {
1739     if (Op == PN)
1740       Ops.push_back(InValue);
1741     else
1742       Ops.push_back(Op->DoPHITranslation(PN->getParent(), InBB));
1743   }
1744 
1745   // Don't consider the simplification successful if we get back a constant
1746   // expression. That's just an instruction in hiding.
1747   // Also reject the case where we simplify back to the phi node. We wouldn't
1748   // be able to remove it in that case.
1749   Value *NewVal = simplifyInstructionWithOperands(
1750       &I, Ops, SQ.getWithInstruction(InBB->getTerminator()));
1751   if (NewVal && NewVal != PN && !match(NewVal, m_ConstantExpr()))
1752     return NewVal;
1753 
1754   // Check if incoming PHI value can be replaced with constant
1755   // based on implied condition.
1756   BranchInst *TerminatorBI = dyn_cast<BranchInst>(InBB->getTerminator());
1757   const ICmpInst *ICmp = dyn_cast<ICmpInst>(&I);
1758   if (TerminatorBI && TerminatorBI->isConditional() &&
1759       TerminatorBI->getSuccessor(0) != TerminatorBI->getSuccessor(1) && ICmp) {
1760     bool LHSIsTrue = TerminatorBI->getSuccessor(0) == PN->getParent();
1761     std::optional<bool> ImpliedCond =
1762         isImpliedCondition(TerminatorBI->getCondition(), ICmp->getPredicate(),
1763                            Ops[0], Ops[1], DL, LHSIsTrue);
1764     if (ImpliedCond)
1765       return ConstantInt::getBool(I.getType(), ImpliedCond.value());
1766   }
1767 
1768   return nullptr;
1769 }
1770 
1771 Instruction *InstCombinerImpl::foldOpIntoPhi(Instruction &I, PHINode *PN) {
1772   unsigned NumPHIValues = PN->getNumIncomingValues();
1773   if (NumPHIValues == 0)
1774     return nullptr;
1775 
1776   // We normally only transform phis with a single use.  However, if a PHI has
1777   // multiple uses and they are all the same operation, we can fold *all* of the
1778   // uses into the PHI.
1779   if (!PN->hasOneUse()) {
1780     // Walk the use list for the instruction, comparing them to I.
1781     for (User *U : PN->users()) {
1782       Instruction *UI = cast<Instruction>(U);
1783       if (UI != &I && !I.isIdenticalTo(UI))
1784         return nullptr;
1785     }
1786     // Otherwise, we can replace *all* users with the new PHI we form.
1787   }
1788 
1789   // Check that all operands are phi-translatable.
1790   for (Value *Op : I.operands()) {
1791     if (Op == PN)
1792       continue;
1793 
1794     // Non-instructions never require phi-translation.
1795     auto *I = dyn_cast<Instruction>(Op);
1796     if (!I)
1797       continue;
1798 
1799     // Phi-translate can handle phi nodes in the same block.
1800     if (isa<PHINode>(I))
1801       if (I->getParent() == PN->getParent())
1802         continue;
1803 
1804     // Operand dominates the block, no phi-translation necessary.
1805     if (DT.dominates(I, PN->getParent()))
1806       continue;
1807 
1808     // Not phi-translatable, bail out.
1809     return nullptr;
1810   }
1811 
1812   // Check to see whether the instruction can be folded into each phi operand.
1813   // If there is one operand that does not fold, remember the BB it is in.
1814   SmallVector<Value *> NewPhiValues;
1815   SmallVector<unsigned int> OpsToMoveUseToIncomingBB;
1816   bool SeenNonSimplifiedInVal = false;
1817   for (unsigned i = 0; i != NumPHIValues; ++i) {
1818     Value *InVal = PN->getIncomingValue(i);
1819     BasicBlock *InBB = PN->getIncomingBlock(i);
1820 
1821     if (auto *NewVal = simplifyInstructionWithPHI(I, PN, InVal, InBB, DL, SQ)) {
1822       NewPhiValues.push_back(NewVal);
1823       continue;
1824     }
1825 
1826     // If the only use of phi is comparing it with a constant then we can
1827     // put this comparison in the incoming BB directly after a ucmp/scmp call
1828     // because we know that it will simplify to a single icmp.
1829     const APInt *Ignored;
1830     if (isa<CmpIntrinsic>(InVal) && InVal->hasOneUser() &&
1831         match(&I, m_ICmp(m_Specific(PN), m_APInt(Ignored)))) {
1832       OpsToMoveUseToIncomingBB.push_back(i);
1833       NewPhiValues.push_back(nullptr);
1834       continue;
1835     }
1836 
1837     if (SeenNonSimplifiedInVal)
1838       return nullptr; // More than one non-simplified value.
1839     SeenNonSimplifiedInVal = true;
1840 
1841     // If there is exactly one non-simplified value, we can insert a copy of the
1842     // operation in that block.  However, if this is a critical edge, we would
1843     // be inserting the computation on some other paths (e.g. inside a loop).
1844     // Only do this if the pred block is unconditionally branching into the phi
1845     // block. Also, make sure that the pred block is not dead code.
1846     BranchInst *BI = dyn_cast<BranchInst>(InBB->getTerminator());
1847     if (!BI || !BI->isUnconditional() || !DT.isReachableFromEntry(InBB))
1848       return nullptr;
1849 
1850     NewPhiValues.push_back(nullptr);
1851     OpsToMoveUseToIncomingBB.push_back(i);
1852 
1853     // If the InVal is an invoke at the end of the pred block, then we can't
1854     // insert a computation after it without breaking the edge.
1855     if (isa<InvokeInst>(InVal))
1856       if (cast<Instruction>(InVal)->getParent() == InBB)
1857         return nullptr;
1858 
1859     // Do not push the operation across a loop backedge. This could result in
1860     // an infinite combine loop, and is generally non-profitable (especially
1861     // if the operation was originally outside the loop).
1862     if (isBackEdge(InBB, PN->getParent()))
1863       return nullptr;
1864   }
1865 
1866   // Clone the instruction that uses the phi node and move it into the incoming
1867   // BB because we know that the next iteration of InstCombine will simplify it.
1868   SmallDenseMap<BasicBlock *, Instruction *> Clones;
1869   for (auto OpIndex : OpsToMoveUseToIncomingBB) {
1870     Value *Op = PN->getIncomingValue(OpIndex);
1871     BasicBlock *OpBB = PN->getIncomingBlock(OpIndex);
1872 
1873     Instruction *Clone = Clones.lookup(OpBB);
1874     if (!Clone) {
1875       Clone = I.clone();
1876       for (Use &U : Clone->operands()) {
1877         if (U == PN)
1878           U = Op;
1879         else
1880           U = U->DoPHITranslation(PN->getParent(), OpBB);
1881       }
1882       Clone = InsertNewInstBefore(Clone, OpBB->getTerminator()->getIterator());
1883       Clones.insert({OpBB, Clone});
1884     }
1885 
1886     NewPhiValues[OpIndex] = Clone;
1887   }
1888 
1889   // Okay, we can do the transformation: create the new PHI node.
1890   PHINode *NewPN = PHINode::Create(I.getType(), PN->getNumIncomingValues());
1891   InsertNewInstBefore(NewPN, PN->getIterator());
